-- 03_discount_rules.sql
CREATE TABLE IF NOT EXISTS discount_rules (
    id                INTEGER PRIMARY KEY,
    payment_software  TEXT,
    payment_method    TEXT,
    user_level        TEXT,
    discount_amount   TEXT,
    min_spend         TEXT,
    equivalent_rate   REAL,
    is_special        INTEGER DEFAULT 0,
    start_date        TEXT,
    end_date          TEXT,
    available_days    TEXT,
    rule_desc         TEXT
);

